// Triggered by Merge News+Cal (after News+Calendar branches complete).
// GET Prices and GET Positions completed earlier (faster FastAPI calls).
const prices    = $('GET Prices').first().json;
const posData   = $('GET Positions').first().json;
const positions = (posData.open || []).concat(posData.pending || []);
const newsItems = $input.all()
  .filter(i => i.json.news)
  .map(i => i.json.news)
  .flat();
const calItems  = $input.all()
  .filter(i => i.json.calendar)
  .map(i => i.json.calendar)
  .flat();
return [{ json: { prices, positions, news: newsItems, calendar: calItems } }];

const input = $input.first().json;
const rawContent = input[0]?.data || input.data || "";
const CURRENCIES = ["EUR","USD","GBP","JPY","CHF","AUD","NZD","CAD","CNY"];
const sourceUrl = 'https://www.forexfactory.com/calendar';

// Only FUTURE events
const today = new Date('2026-06-04T00:00:00Z');
const monthNames = {Jan:1, Feb:2, Mar:3, Apr:4, May:5, Jun:6, Jul:7, Aug:8, Sep:9, Oct:10, Nov:11, Dec:12};

function parseEventDate(dateStr) {
  const match = dateStr.match(/(Sun|Mon|Tue|Wed|Thu|Fri|Sat)\s(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\s(\d+)/);
  if (!match) return null;
  const [, dow, mon, day] = match;
  const month = monthNames[mon];
  const year = month < 6 ? 2026 : 2026;
  return new Date(Date.UTC(year, month - 1, parseInt(day)));
}

const lines = rawContent.split('\n');
let currentDate = '';
const calendar = [];

for (const line of lines) {
  if (!line.includes('|')) continue;
  const cells = line.split('|').map(c => c.trim()).filter(c => c !== '');

  if (cells.length < 3 || line.includes('---')) continue;
  const firstCell = cells[0] || '';

  // Skip headers and junk
  if (/^(Date|Actual|\[5:00am|Time)/i.test(firstCell)) continue;
  if (firstCell === '' && cells.length <= 2) continue;

  // Detect date rows
  if (firstCell.match(/^(Sun|Mon|Tue|Wed|Thu|Fri|Sat|Tentative)\s/)) {
    currentDate = firstCell;
    const eventDate = parseEventDate(firstCell);
    // SKIP PAST DATES
    if (eventDate && eventDate < today) {
      currentDate = '';
      continue;
    }
    continue;
  }

  if (!currentDate) continue;

  // Find currency
  let currencyIdx = -1;
  for (let i = 0; i < Math.min(4, cells.length); i++) {
    if (CURRENCIES.some(c => cells[i].includes(c))) {
      currencyIdx = i;
      break;
    }
  }

  if (currencyIdx === -1) continue;

  let time = currencyIdx > 0 ? cells[currencyIdx - 1] : '';
  let currency = CURRENCIES.find(c => cells[currencyIdx].includes(c)) || '';

  if (!currency) continue;

  // Extract clean event name
  let eventName = '';
  for (let i = currencyIdx + 1; i < cells.length; i++) {
    let cell = cells[i] || '';
    cell = cell.replace(/!\[Image \d+\][^\]]*\]/g, '');
    cell = cell.replace(/\[!\[Image \d+\][^\]]*\]\([^)]*\)/g, '');
    cell = cell.replace(/\[\(https[^)]*\)/g, '');
    cell = cell.trim();

    if (!cell || cell.length < 3) continue;
    if (cell.match(/^[0-9%.KMBD|-]+$/)) continue;
    if (/Detail|Graph|Alerts/i.test(cell)) continue;
    if (cell.startsWith('http')) continue;

    eventName = cell.slice(0, 80);
    break;
  }

  if (!eventName) continue;

  const impact = line.includes('ff-impact-red') ? 'high' :
                 line.includes('ff-impact-ora') ? 'high' :
                 line.includes('ff-impact-yel') ? 'medium' : 'low';

  // Extract and CLEAN numbers
  const numValues = [];
  for (let i = currencyIdx + 1; i < cells.length; i++) {
    let cell = cells[i];
    if (cell && cell.match(/^[+-]?[\d.]+%?[KMBD]?(\|[\d.]+)?$/)) {
      cell = cell.replace(/\s*!\[Image[^\]]*\]/g, '');
      cell = cell.trim();
      if (cell) numValues.push(cell);
    }
  }

  let actual = '', forecast = '', previous = '';
  if (numValues.length >= 3) {
    actual = numValues[numValues.length - 3];
    forecast = numValues[numValues.length - 2];
    previous = numValues[numValues.length - 1];
  } else if (numValues.length === 2) {
    forecast = numValues[0];
    previous = numValues[1];
  } else if (numValues.length === 1) {
    forecast = numValues[0];
  }

  calendar.push({
    event: eventName,
    currency,
    impact,
    time,
    date: currentDate,
    utc_offset: '',
    forecast,
    actual,
    previous,
    source_url: sourceUrl
  });

  if (calendar.length >= 10) break;
}

return [{ json: { calendar } }];

const input = $input.first().json;
const rawContent = input[0]?.data || input.data || "";
const CURRENCIES = ["EUR","USD","GBP","JPY","CHF","AUD","NZD","CAD"];
const sourceUrl = 'https://www.forexlive.com/feed/news';

// Dividir por URLs (que empiezan con [https)
const urlPattern = /\[https:\/\/investinglive\.com\/news\/([^\]]+)\]/g;
const matches = [];
let match;
while ((match = urlPattern.exec(rawContent)) !== null) {
  matches.push(match[1]);
}

const news = [];
for (const urlSlug of matches.slice(0, 10)) {
  // Reconstruir headline de la URL (reemplazar guiones por espacios, capitalizar)
  const headline = urlSlug
    .split('-')
    .slice(0, -1)  // remover timestamp
    .join(' ')
    .slice(0, 140);

  if (!headline || headline.length < 10) continue;

  // Buscar moneda en todo el contenido
  const currency = CURRENCIES.find(c => rawContent.toUpperCase().includes(c)) || "";

  // Detectar impact
  const impact = rawContent.toLowerCase().includes("high") ? "high" : 
                 rawContent.toLowerCase().includes("medium") ? "medium" : "low";

  news.push({
    headline: headline.trim(),
    impact,
    currency,
    source_url: sourceUrl,
    content: headline
  });
}

return [{ json: { news } }];
